#include <bits/stdc++.h>
using namespace std;
int n,q;
int main() {
	string s,p;
	cin>>n>>q;
	cin>>s>>p;
	int len=s.size();
	int tj1=0,tj2=0;
	for(int i =0; i<p.size() ; i++) {
		if(p[i]=='1') {
			tj1++;
		} else tj2++;
	}
	if(tj1%2==1) {
		for(int j=0; j<len/2; j++) {
			swap(s[j],s[len-j-1]);
		}
	}
	if(tj2%2==1) {
		for(int j=0; j<len; j++) {
			s[j]=!(s[j]-'0')+'0';
		}
	}
	cout<<s;
	return 0;
}
